package com.lugatek.thubanlodestar.widgets.opengl;
import android.content.*;import android.graphics.*;import android.util.*;import android.view.*;
public class ModelSurfaceView extends View{ Paint p=new Paint(1),g=new Paint(1),txt=new Paint(1); float level=0; public ModelSurfaceView(Context c){super(c);init();} public ModelSurfaceView(Context c,AttributeSet a){super(c,a);init();} void init(){p.setStyle(Paint.Style.FILL);g.setStyle(Paint.Style.STROKE);g.setStrokeWidth(2);g.setColor(Color.rgb(64,82,103));txt.setColor(Color.WHITE);txt.setTextSize(32);} public void setLevel(float l){level=l;invalidate();} protected void onDraw(Canvas c){c.drawColor(Color.rgb(10,14,22));int w=getWidth(),h=getHeight();for(int i=0;i<8;i++){float y=h*(i+1)/9f;c.drawLine(0,y,w,y,g);float x=w*(i+1)/9f;c.drawLine(x,0,x,h,g);}float r=Math.min(w,h)*(0.12f+Math.min(1,level/40f)*0.32f);p.setColor(Color.rgb(0,(int)Math.max(80,220-level*2),255));c.drawCircle(w/2f,h/2f,r,p);g.setColor(Color.argb(130,255,255,255));c.drawCircle(w/2f,h/2f,r*1.35f,g);c.drawText("3D / SONAR YÜZEY",20,42,txt);c.drawText(String.format("Anomali: %.1f µT",level),20,h-22,txt);} }
